import java.io.*;

public class CommandInjection {

    // VULNERABLE: User input passed directly to shell
    public static String lookupDNS_vulnerable(String domain) {
        try {
            // This passes the command through the shell!
            Process proc = Runtime.getRuntime().exec(
                new String[]{"/bin/sh", "-c", "nslookup " + domain});

            BufferedReader reader = new BufferedReader(
                new InputStreamReader(proc.getInputStream()));

            StringBuilder output = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                output.append(line).append("\n");
            }
            return output.toString();
        } catch (IOException e) {
            return "Error: " + e.getMessage();
        }
    }

    // SECURE: No shell, direct command execution
    public static String lookupDNS_secure(String domain) {
        try {
            // Array form - each argument is separate, no shell
            Process proc = Runtime.getRuntime().exec(
                new String[]{"nslookup", domain});

            BufferedReader reader = new BufferedReader(
                new InputStreamReader(proc.getInputStream()));

            StringBuilder output = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                output.append(line).append("\n");
            }
            return output.toString();
        } catch (IOException e) {
            return "Error";
        }
    }

    public static void main(String[] args) {
        String maliciousInput = "google.com; cat /etc/passwd";

        System.out.println("=== VULNERABLE ===");
        System.out.println(lookupDNS_vulnerable(maliciousInput));

        System.out.println("=== SECURE ===");
        System.out.println(lookupDNS_secure(maliciousInput));
    }
}

import java.sql.*;

public class SecondOrderInjection {

    // Step 1: Registration - safely stored using PreparedStatement!
    public static void register(Connection conn, String user, String email) 
            throws SQLException {
        PreparedStatement ps = conn.prepareStatement(
            "INSERT INTO users (username, email) VALUES (?, ?)");
        ps.setString(1, user);   // Safe! Uses PreparedStatement
        ps.setString(2, email);  // Safe! Uses PreparedStatement
        ps.executeUpdate();
        System.out.println("Registered: " + user);
    }

    // Step 2: Profile view - VULNERABLE! Reads stored data unsafely
    public static void viewProfile(Connection conn, int userId) 
            throws SQLException {
        // First, get the username from the database
        PreparedStatement ps1 = conn.prepareStatement(
            "SELECT username FROM users WHERE id = ?");
        ps1.setInt(1, userId);
        ResultSet rs1 = ps1.executeQuery();

        if (rs1.next()) {
            String username = rs1.getString("username");

            // VULNERABLE! The username from DB is trusted and concatenated!
            Statement stmt = conn.createStatement();
            String query = "SELECT * FROM orders WHERE customer = '" 
                + username + "'";
            System.out.println("Order query: " + query);
            ResultSet rs2 = stmt.executeQuery(query);
            // ... process orders
        }
    }

    public static void main(String[] args) throws Exception {
        // Attacker registers with malicious username
        // Username: admin' OR '1'='1' --
        // This is STORED safely in the users table
        // But when viewProfile() uses it in another query... BOOM!
        System.out.println("Attacker registers with username:");
        System.out.println("admin' OR '1'='1' --");
        System.out.println();
        System.out.println("Later, when profile is viewed:");
        System.out.println("SELECT * FROM orders WHERE customer = '"
            + "admin' OR '1'='1' --" + "'");
        System.out.println("= Returns ALL orders from ALL customers!");
    }
}

