            "admin' AND SUBSTRING(password,1,1)='s' --", "x");
    }
}

import java.sql.*;
import java.util.logging.Logger;

public class ResultVerification {
    private static final Logger logger = Logger.getLogger("Security");

    public static boolean secureLogin(Connection conn, 
            String user, String hashedPwd) throws SQLException {

        // Layer 1: PreparedStatement
        PreparedStatement ps = conn.prepareStatement(
            "SELECT * FROM users WHERE username=? AND password_hash=?");
        ps.setString(1, user);
        ps.setString(2, hashedPwd);

        ResultSet rs = ps.executeQuery();

        // Layer 4: Result Count Verification
        int rowCount = 0;
        String foundUser = null;
        while (rs.next()) {
            rowCount++;
            foundUser = rs.getString("username");
        }

        if (rowCount == 0) {
            logger.info("Failed login attempt for: " + user);
            return false;
        } else if (rowCount == 1) {
            logger.info("Successful login: " + foundUser);
            return true;
        } else {
            // More than 1 row? Something is VERY wrong!
            logger.severe("SECURITY ALERT: Login query returned " 
                + rowCount + " rows for user: " + user 
                + " - Possible injection attack!");
            throw new SecurityException("Authentication error");
        }
    }

    public static void main(String[] args) {
        System.out.println("Normal login: expects 0 or 1 rows");
        System.out.println("If OR 1=1 somehow bypassed PreparedStatement:");
        System.out.println("  -> Would return ALL rows (e.g., 500)");
        System.out.println("  -> rowCount > 1 triggers SECURITY ALERT");
        System.out.println("  -> Login DENIED + incident logged");
    }
}

import java.sql.*;
import java.util.*;

public class WhitelistDefence {

    // Whitelist of allowed table names
    private static final Set<String> ALLOWED_TABLES = Set.of(
        "products", "categories", "reviews"
    );

    // Whitelist of allowed sort columns
    private static final Set<String> ALLOWED_SORT_COLUMNS = Set.of(
        "name", "price", "rating", "date_added"
    );

    // VULNERABLE: Table name from user input
    public static void searchVulnerable(Connection conn, 
            String table, String sortBy) throws SQLException {
        // CAN'T use ? for table names!
        String query = "SELECT * FROM " + table 
            + " ORDER BY " + sortBy;
        Statement stmt = conn.createStatement();
        stmt.executeQuery(query);  // Attacker controls table AND sort!
    }

    // SECURE: Whitelist validation
    public static void searchSecure(Connection conn, 
            String table, String sortBy) throws SQLException {

        // Validate table name against whitelist
        if (!ALLOWED_TABLES.contains(table.toLowerCase())) {
            throw new SecurityException(
                "Invalid table: " + table);
        }

        // Validate sort column against whitelist
        if (!ALLOWED_SORT_COLUMNS.contains(sortBy.toLowerCase())) {
            throw new SecurityException(
                "Invalid sort column: " + sortBy);
        }

        // Safe to use - values are from our whitelist
        String query = "SELECT * FROM " + table 
            + " ORDER BY " + sortBy;
        Statement stmt = conn.createStatement();
        stmt.executeQuery(query);
    }

    public static void main(String[] args) {
        System.out.println("=== Vulnerable ===");
        System.out.println("table='users; DROP TABLE users --'");
        System.out.println("Query: SELECT * FROM users; DROP TABLE users -- ORDER BY name");
        System.out.println("Result: TABLE DELETED!\n");

        System.out.println("=== Secure (Whitelist) ===");
        System.out.println("table='users; DROP TABLE users --'");
        System.out.println("Result: SecurityException - Invalid table!");
    }
}

import java.sql.*;

public class StoredProcedureDefence {

    // SQL to create the stored procedure (run once in DB setup):
    // CREATE PROCEDURE authenticate(
    //     IN p_username VARCHAR(50),
    //     IN p_password VARCHAR(255)
    // )
    // BEGIN
    //     SELECT id, username, role FROM users 
    //     WHERE username = p_username 
    //     AND password_hash = SHA2(p_password, 256);
    // END

    public static boolean login(Connection conn, 
            String user, String pwd) throws SQLException {

        // Call stored procedure - no raw SQL in application!
        CallableStatement cs = conn.prepareCall(
            "{call authenticate(?, ?)}");
        cs.setString(1, user);
        cs.setString(2, pwd);

        ResultSet rs = cs.executeQuery();

        if (rs.next()) {
            String role = rs.getString("role");
            System.out.println("Authenticated as: " + user 
                + " (role: " + role + ")");
            return true;
        }
        return false;
    }

    public static void main(String[] args) {
        System.out.println("Benefits of Stored Procedures:");
        System.out.println("1. SQL is in the database, not the application");
        System.out.println("2. Application only calls by name with parameters");
        System.out.println("3. Database controls what operations are allowed");
        System.out.println("4. Reduced attack surface");
        System.out.println("5. Can enforce additional security logic in DB");
        System.out.println();
        System.out.println("The application never sees raw SQL.");
        System.out.println("Even if the app is compromised, the attacker");
        System.out.println("can only call procedures that already exist.");
    }
}

public class LeastPrivilege {

    public static void main(String[] args) {
        System.out.println("=== BAD: Application uses admin account ===");
        System.out.println("Connection: jdbc:mysql://db?user=root&password=admin123");
        System.out.println("Permissions: ALL PRIVILEGES ON *.*");
        System.out.println("If SQL injection succeeds, attacker can:");
        System.out.println("  - Read ANY table in ANY database");
        System.out.println("  - Modify or delete ANY data");
        System.out.println("  - Create new admin accounts");
        System.out.println("  - Drop entire databases");
        System.out.println("  - Execute OS commands via xp_cmdshell");
        System.out.println();

        System.out.println("=== GOOD: Separate accounts per function ===");
        System.out.println();

        System.out.println("Login Service Account:");
        System.out.println("  CREATE USER 'app_login'@'localhost';");
        System.out.println("  GRANT SELECT ON myapp.users TO 'app_login'@'localhost';");
        System.out.println("  -> Can ONLY read users table. Nothing else.");
        System.out.println();

        System.out.println("Product Service Account:");
        System.out.println("  CREATE USER 'app_products'@'localhost';");
        System.out.println("  GRANT SELECT ON myapp.products TO 'app_products'@'localhost';");
        System.out.println("  GRANT SELECT ON myapp.categories TO 'app_products'@'localhost';");
        System.out.println("  -> Can only read products and categories.");
