import java.io.*;
import java.util.*;

public class SecureCommandExecution {

    // OPTION 1: Use API instead of external command (BEST)
    public static String dnsLookup_api(String domain) {
        try {
            java.net.InetAddress addr = java.net.InetAddress.getByName(domain);
            return "IP: " + addr.getHostAddress();
        } catch (Exception e) {
            return "Lookup failed";
        }
    }

    // OPTION 2: ProcessBuilder with argument separation (GOOD)
    public static String dnsLookup_processBuilder(String domain) {
        try {
            // Each argument is separate - no shell involved
            ProcessBuilder pb = new ProcessBuilder("nslookup", domain);
            pb.redirectErrorStream(true);
            Process proc = pb.start();

            BufferedReader reader = new BufferedReader(
                new InputStreamReader(proc.getInputStream()));
            StringBuilder output = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                output.append(line).append("\n");
            }

            int exitCode = proc.waitFor();
            if (exitCode != 0) {
                return "Command failed with exit code: " + exitCode;
            }
            return output.toString();
        } catch (Exception e) {
            return "Error";
        }
    }

    // OPTION 3: Input validation + ProcessBuilder (BEST for external commands)
    public static String dnsLookup_validated(String domain) {
        // Whitelist: only allow valid domain characters
        if (!domain.matches("^[a-zA-Z0-9][a-zA-Z0-9.-]{1,253}[a-zA-Z0-9]$")) {
            return "Invalid domain format";
        }
        return dnsLookup_processBuilder(domain);
    }

    public static void main(String[] args) {
        String safe = "google.com";
        String malicious = "google.com; cat /etc/passwd";

        System.out.println("=== API (no command at all) ===");
        System.out.println(dnsLookup_api(safe));
        System.out.println(dnsLookup_api(malicious)); // Fails safely

        System.out.println("\n=== ProcessBuilder (no shell) ===");
        System.out.println("Safe: " + dnsLookup_processBuilder(safe));
        System.out.println("Attack: " + dnsLookup_processBuilder(malicious));

        System.out.println("\n=== Validated + ProcessBuilder ===");
        System.out.println("Attack: " + dnsLookup_validated(malicious));
    }
}

import java.sql.*;
import java.util.logging.Logger;

public class SecureCRUD {
    private static final Logger log = Logger.getLogger("SecureCRUD");
    private Connection conn;

    public SecureCRUD(Connection conn) { this.conn = conn; }

    // CREATE - with validation
    public int addUser(String username, String email) throws SQLException {
        if (!username.matches("^[a-zA-Z0-9_]{3,20}$"))
            throw new IllegalArgumentException("Invalid username");
        if (!email.matches("^[\\w.+-]+@[\\w-]+\\.[\\w.]+$"))
            throw new IllegalArgumentException("Invalid email");

        PreparedStatement ps = conn.prepareStatement(
            "INSERT INTO users (username, email) VALUES (?, ?)",
            Statement.RETURN_GENERATED_KEYS);
        ps.setString(1, username);
        ps.setString(2, email);
        ps.executeUpdate();

        ResultSet keys = ps.getGeneratedKeys();
        return keys.next() ? keys.getInt(1) : -1;
    }

    // READ - with PreparedStatement
    public String findUser(int id) throws SQLException {
        PreparedStatement ps = conn.prepareStatement(
            "SELECT username, email FROM users WHERE id = ?");
        ps.setInt(1, id);
        ResultSet rs = ps.executeQuery();

        if (rs.next()) {
            return rs.getString("username") + " <" + rs.getString("email") + ">";
        }
        return null;
    }

    // UPDATE - with validation + PreparedStatement
    public boolean updateEmail(int id, String newEmail) throws SQLException {
        if (!newEmail.matches("^[\\w.+-]+@[\\w-]+\\.[\\w.]+$"))
            throw new IllegalArgumentException("Invalid email");

        PreparedStatement ps = conn.prepareStatement(
            "UPDATE users SET email = ? WHERE id = ?");
        ps.setString(1, newEmail);
        ps.setInt(2, id);
        int updated = ps.executeUpdate();

        if (updated != 1) {
            log.warning("Update affected " + updated + " rows for id: " + id);
        }
        return updated == 1;
    }

    // DELETE - with verification
    public boolean deleteUser(int id) throws SQLException {
        PreparedStatement ps = conn.prepareStatement(
            "DELETE FROM users WHERE id = ?");
        ps.setInt(1, id);
        int deleted = ps.executeUpdate();

        if (deleted > 1) {
            log.severe("ALERT: Delete removed " + deleted + " rows!");
            throw new SecurityException("Unexpected delete count");
        }
        return deleted == 1;
    }

    public static void main(String[] args) {
        System.out.println("Secure CRUD Pattern:");
        System.out.println("1. Validate input BEFORE database operations");
        System.out.println("2. Use PreparedStatement for ALL queries");
        System.out.println("3. Use setString/setInt (never concatenate)");
        System.out.println("4. Verify affected row counts");
        System.out.println("5. Log anomalies for security monitoring");
        System.out.println("6. Show generic errors to users");
    }
}

