import java.sql.*;

public class ErrorLeakage {

    // VULNERABLE: Shows raw database errors to user
    public static void searchVulnerable(String input) {
        try {
            Connection conn = DriverManager.getConnection("jdbc:sqlite:shop.db");
            Statement stmt = conn.createStatement();
            String query = "SELECT * FROM products WHERE id = " + input;
            stmt.executeQuery(query);
        } catch (SQLException e) {
            // DANGER: This reveals internal information!
            System.out.println("Error: " + e.getMessage());
        }
    }

    // SECURE: Generic error with log reference
    public static void searchSecure(String input) {
        try {
            Connection conn = DriverManager.getConnection("jdbc:sqlite:shop.db");
            PreparedStatement ps = conn.prepareStatement(
                "SELECT * FROM products WHERE id = ?");
            ps.setInt(1, Integer.parseInt(input));
            ps.executeQuery();
        } catch (NumberFormatException e) {
            System.out.println("Please enter a valid product number.");
        } catch (SQLException e) {
            String ref = "ERR-" + System.currentTimeMillis();
            // Log the real error internally
            System.err.println("[" + ref + "] DB Error: " + e.getMessage());
            // Show generic message to user
            System.out.println("An error occurred. Reference: " + ref);
        }
    }

    public static void main(String[] args) {
        System.out.println("=== VULNERABLE: Error Leakage ===");
        System.out.println("Input: ' UNION SELECT 1,2,3 --");
        System.out.println("Error: SQLite error: SELECTs to the left and right");
        System.out.println("       of UNION do not have the same number of");
        System.out.println("       result columns (4 vs 3)");
        System.out.println("  -> Attacker now knows: table has 4 columns!\n");

        System.out.println("=== SECURE: Generic Error ===");
        System.out.println("Input: ' UNION SELECT 1,2,3 --");
        System.out.println("Please enter a valid product number.");
        System.out.println("  -> Attacker learns NOTHING.");
    }
}

